final:
module top_module (
    input j,
    input t,
    input k,
    output reg nb
);
    always @(*) begin
        case ({j, t, k})
            3'b000: nb = 1'b1;
            3'b111: nb = 1'b0;
            3'b110: nb = 1'b0;
            3'b001: nb = 1'b1;
            3'b011: nb = 1'b1;
            3'b100: nb = 1'b1;
            3'b010: nb = 1'b0;
            3'b101: nb = 1'b1;
        endcase
    end
endmodule
